    59→	conn *grpc.ClientConn
    60→
    61→	cfg      Config
    62→	creds    grpccredentials.TransportCredentials
    63→	resolver *resolver.EtcdManualResolver
    64→
    65→	epMu      *sync.RWMutex
    66→	endpoints []string
    67→
    68→	ctx    context.Context
    69→	cancel context.CancelFunc
    70→
    71→	// Username is a user name for authentication.
    72→	Username string
    73→	// Password is a password for authentication.
    74→	Password string
    75→	// Token is a JWT used for authentication instead of a password.
    76→	Token string
