    84→
    85→// New creates a new etcdv3 client from a given configuration.
    86→func New(cfg Config) (*Client, error) {
    87→	if len(cfg.Endpoints) == 0 {
    88→		return nil, ErrNoAvailableEndpoints
    89→	}
    90→
    91→	return newClient(&cfg)
    92→}
    93→
    94→// NewCtxClient creates a client with a context but no underlying grpc
    95→// connection. This is useful for embedded cases that override the
    96→// service interface implementations and do not need connection management.
    97→func NewCtxClient(ctx context.Context, opts ...Option) *Client {
    98→	cctx, cancel := context.WithCancel(ctx)
    99→	c := &Client{ctx: cctx, cancel: cancel, epMu: new(sync.RWMutex)}
   100→	for _, opt := range opts {
   101→		opt(c)
   102→	}
   103→	if c.lg.Load() == nil {
   104→		c.lg.Store(zap.NewNop())
   105→	}
   106→	return c
   107→}
   108→
   109→// Option is a function type that can be passed as argument to NewCtxClient to configure client
   110→type Option func(*Client)
   111→
   112→// NewFromURL creates a new etcdv3 client from a URL.
   113→func NewFromURL(url string) (*Client, error) {
   114→	return New(Config{Endpoints: []string{url}})
   115→}
   116→
   117→// NewFromURLs creates a new etcdv3 client from URLs.
   118→func NewFromURLs(urls []string) (*Client, error) {
   119→	return New(Config{Endpoints: urls})
   120→}
   121→
   122→// WithZapLogger is a NewCtxClient option that overrides the logger
   123→func WithZapLogger(lg *zap.Logger) Option {
   124→	return func(c *Client) {
   125→		c.lg.Store(lg)
   126→	}
   127→}
   128→
   129→// WithLogger overrides the logger.
   130→//
   131→// Deprecated: Please use WithZapLogger or Logger field in clientv3.Config
   132→//
   133→// Does not changes grpcLogger, that can be explicitly configured
   134→// using grpc_zap.ReplaceGrpcLoggerV2(..) method.
   135→func (c *Client) WithLogger(lg *zap.Logger) *Client {
   136→	c.lg.Store(lg)
   137→	return c
   138→}
   139→
   140→// GetLogger gets the logger.
   141→// NOTE: This method is for internal use of etcd-client library and should not be used as general-purpose logger.
   142→func (c *Client) GetLogger() *zap.Logger {
   143→	return c.lg.Load()
   144→}
   145→
   146→// Close shuts down the client's etcd connections.
   147→func (c *Client) Close() error {
   148→	c.cancel()
   149→	if c.Watcher != nil {
   150→		c.Watcher.Close()
   151→	}
   152→	if c.Lease != nil {
   153→		c.Lease.Close()
   154→	}
   155→	if c.conn != nil {
   156→		return ContextError(c.ctx, c.conn.Close())
   157→	}
   158→	return c.ctx.Err()
   159→}
   160→
   161→// Ctx is a context for "out of band" messages (e.g., for sending
   162→// "clean up" message when another context is canceled). It is
   163→// canceled on client Close().
   164→func (c *Client) Ctx() context.Context { return c.ctx }
   165→
   166→// Endpoints lists the registered endpoints for the client.
   167→func (c *Client) Endpoints() []string {
   168→	// copy the slice; protect original endpoints from being changed
   169→	c.epMu.RLock()
   170→	defer c.epMu.RUnlock()
   171→	eps := make([]string, len(c.endpoints))
   172→	copy(eps, c.endpoints)
   173→	return eps
   174→}
   175→
   176→// SetEndpoints updates client's endpoints.
   177→func (c *Client) SetEndpoints(eps ...string) {
   178→	c.epMu.Lock()
   179→	defer c.epMu.Unlock()
   180→	c.endpoints = eps
   181→
   182→	c.resolver.SetEndpoints(eps)
   183→}
   184→
   185→// Sync synchronizes client's endpoints with the known endpoints from the etcd membership.
   186→func (c *Client) Sync(ctx context.Context) error {
   187→	mresp, err := c.MemberList(ctx)
   188→	if err != nil {
   189→		return err
   190→	}
   191→	var eps []string
   192→	for _, m := range mresp.Members {
   193→		if len(m.Name) != 0 && !m.IsLearner {
   194→			eps = append(eps, m.ClientURLs...)
   195→		}
   196→	}
   197→	// The linearizable `MemberList` returned successfully, so the
   198→	// endpoints shouldn't be empty.
   199→	verify.Verify("empty endpoints returned from etcd cluster", func() (bool, map[string]any) {
   200→		return len(eps) > 0, nil
   201→	})
   202→	c.SetEndpoints(eps...)
   203→	c.GetLogger().Debug("set etcd endpoints by autoSync", zap.Strings("endpoints", eps))
   204→	return nil
   205→}
   206→
   207→func (c *Client) autoSync() {
   208→	if c.cfg.AutoSyncInterval == time.Duration(0) {
   209→		return
   210→	}
   211→
   212→	for {
   213→		select {
   214→		case <-c.ctx.Done():
   215→			return
   216→		case <-time.After(c.cfg.AutoSyncInterval):
   217→			ctx, cancel := context.WithTimeout(c.ctx, 5*time.Second)
   218→			err := c.Sync(ctx)
   219→			cancel()
   220→			if err != nil && !errors.Is(err, c.ctx.Err()) {
   221→				c.GetLogger().Info("Auto sync endpoints failed.", zap.Error(err))
   222→			}
   223→		}
   224→	}
   225→}
   226→
   227→// dialSetupOpts gives the dial opts prior to any authentication.
   228→func (c *Client) dialSetupOpts(creds grpccredentials.TransportCredentials, dopts ...grpc.DialOption) []grpc.DialOption {
   229→	var opts []grpc.DialOption
   230→
   231→	if c.cfg.DialKeepAliveTime > 0 {
   232→		params := keepalive.ClientParameters{
   233→			Time:                c.cfg.DialKeepAliveTime,
   234→			Timeout:             c.cfg.DialKeepAliveTimeout,
   235→			PermitWithoutStream: c.cfg.PermitWithoutStream,
   236→		}
   237→		opts = append(opts, grpc.WithKeepaliveParams(params))
   238→	}
   239→	opts = append(opts, dopts...)
   240→
   241→	if creds != nil {
   242→		opts = append(opts, grpc.WithTransportCredentials(creds))
   243→	} else {
   244→		opts = append(opts, grpc.WithTransportCredentials(insecure.NewCredentials()))
   245→	}
   246→
   247→	unaryMaxRetries := defaultUnaryMaxRetries
   248→	if c.cfg.MaxUnaryRetries > 0 {
   249→		unaryMaxRetries = c.cfg.MaxUnaryRetries
   250→	}
   251→
   252→	backoffWaitBetween := defaultBackoffWaitBetween
   253→	if c.cfg.BackoffWaitBetween > 0 {
   254→		backoffWaitBetween = c.cfg.BackoffWaitBetween
   255→	}
   256→
   257→	backoffJitterFraction := defaultBackoffJitterFraction
   258→	if c.cfg.BackoffJitterFraction > 0 {
   259→		backoffJitterFraction = c.cfg.BackoffJitterFraction
   260→	}
   261→
   262→	// Interceptor retry and backoff.
   263→	// TODO: Replace all of clientv3/retry.go with RetryPolicy:
   264→	// https://github.com/grpc/grpc-proto/blob/cdd9ed5c3d3f87aef62f373b93361cf7bddc620d/grpc/service_config/service_config.proto#L130
   265→	rrBackoff := withBackoff(c.roundRobinQuorumBackoff(backoffWaitBetween, backoffJitterFraction))
   266→	opts = append(opts,
   267→		// Disable stream retry by default since go-grpc-middleware/retry does not support client streams.
   268→		// Streams that are safe to retry are enabled individually.
   269→		grpc.WithStreamInterceptor(c.streamClientInterceptor(withMax(0), rrBackoff)),
   270→		grpc.WithUnaryInterceptor(c.unaryClientInterceptor(withMax(unaryMaxRetries), rrBackoff)),
   271→	)
   272→
   273→	return opts
   274→}
