   327→	dctx := c.ctx
   328→	if c.cfg.DialTimeout > 0 {
   329→		var cancel context.CancelFunc
   330→		dctx, cancel = context.WithTimeout(c.ctx, c.cfg.DialTimeout)
   331→		defer cancel() // TODO: Is this right for cases where grpc.WithBlock() is not set on the dial options?
   332→	}
   333→	target := fmt.Sprintf("%s://%p/%s", resolver.Schema, c, authority(c.endpoints[0]))
   334→	conn, err := grpc.DialContext(dctx, target, opts...) //nolint:staticcheck // TODO: remove for a supported version
   335→	if err != nil {
   336→		return nil, err
   337→	}
