   355→func (c *Client) credentialsForEndpoint(ep string) grpccredentials.TransportCredentials {
   356→	r := endpoint.RequiresCredentials(ep)
   357→	switch r {
   358→	case endpoint.CredsDrop:
   359→		return nil
   360→	case endpoint.CredsOptional:
   361→		return c.creds
   362→	case endpoint.CredsRequire:
   363→		if c.creds != nil {
   364→			return c.creds
   365→		}
   366→		return credentials.NewTransportCredential(nil)
   367→	default:
   368→		panic(fmt.Errorf("unsupported CredsRequirement: %v", r))
   369→	}
