   499→// roundRobinQuorumBackoff retries against quorum between each backoff.
   500→// This is intended for use with a round robin load balancer.
   501→func (c *Client) roundRobinQuorumBackoff(waitBetween time.Duration, jitterFraction float64) backoffFunc {
   502→	return func(attempt uint) time.Duration {
   503→		// after each round robin across quorum, backoff for our wait between duration
   504→		n := uint(len(c.Endpoints()))
   505→		quorum := (n/2 + 1)
   506→		if attempt%quorum == 0 {
   507→			c.GetLogger().Debug("backoff", zap.Uint("attempt", attempt), zap.Uint("quorum", quorum), zap.Duration("waitBetween", waitBetween), zap.Float64("jitterFraction", jitterFraction))
   508→			return jitterUp(waitBetween, jitterFraction)
   509→		}
   510→		c.GetLogger().Debug("backoff skipped", zap.Uint("attempt", attempt), zap.Uint("quorum", quorum))
   511→		return 0
   512→	}
   513→}
