   714→func isFinalError(err error) bool {
   715→	// Sources:
   716→	// https://github.com/grpc/grpc/blob/master/doc/statuscodes.md
   717→	// https://github.com/container-storage-interface/spec/blob/master/spec.md
   718→	st, ok := status.FromError(err)
   719→	if !ok {
   720→		// This is not gRPC error. The operation must have failed before gRPC
   721→		// method was called, otherwise we would get gRPC error.
   722→		// We don't know if any previous volume operation is in progress, be on the safe side.
   723→		return false
   724→	}
   725→	switch st.Code() {
   726→	case codes.Canceled, // gRPC: Client Application cancelled the request
   727→		codes.DeadlineExceeded,  // gRPC: Timeout
   728→		codes.Unavailable,       // gRPC: Server shutting down, TCP connection broken - previous volume operation may be still in progress.
   729→		codes.ResourceExhausted, // gRPC: Server temporarily out of resources - previous volume operation may be still in progress.
   730→		codes.Aborted:           // CSI: Operation pending for volume
   731→		return false
   732→	}
   733→	// All other errors mean that operation either did not
   734→	// even start or failed. It is for sure not in progress.
   735→	return true
   736→}
