   423→func (d *dummyListener) waitForCount(t *testing.T, expect int) {
   424→	t.Helper()
   425→	err := wait.PollUntilContextTimeout(context.Background(), time.Millisecond, 10*time.Second, true, func(_ context.Context) (bool, error) {
   426→		actual := int(d.count.Load())
   427→		switch {
   428→		case actual > expect:
   429→			return false, fmt.Errorf("expected %d broadcasts, got %d broadcasts", expect, actual)
   430→		case actual == expect:
   431→			return true, nil
   432→		default:
   433→			t.Logf("expected %d broadcasts, got %d broadcasts, waiting...", expect, actual)
   434→			return false, nil
   435→		}
   436→	})
   437→	if err != nil {
   438→		t.Fatal(err)
   439→	}
   440→}
