   446→func TestKeysChanged(t *testing.T) {
   447→	testcases := []struct {
   448→		name    string
   449→		oldKeys VerificationKeys
   450→		newKeys VerificationKeys
   451→		expect  bool
   452→	}{
   453→		{
   454→			name:    "empty",
   455→			oldKeys: VerificationKeys{},
   456→			newKeys: VerificationKeys{},
   457→			expect:  false,
   458→		},
   459→		{
   460→			name:    "identical",
   461→			oldKeys: VerificationKeys{DataTimestamp: time.Unix(1000, 0), Keys: []serviceaccount.PublicKey{{KeyID: "a"}, {KeyID: "b"}}},
   462→			newKeys: VerificationKeys{DataTimestamp: time.Unix(1000, 0), Keys: []serviceaccount.PublicKey{{KeyID: "a"}, {KeyID: "b"}}},
   463→			expect:  false,
   464→		},
   465→		{
   466→			name:    "changed datatimestamp",
   467→			oldKeys: VerificationKeys{DataTimestamp: time.Unix(1000, 0), Keys: []serviceaccount.PublicKey{{KeyID: "a"}, {KeyID: "b"}}},
   468→			newKeys: VerificationKeys{DataTimestamp: time.Unix(1001, 0), Keys: []serviceaccount.PublicKey{{KeyID: "a"}, {KeyID: "b"}}},
   469→			expect:  true,
   470→		},
   471→		{
   472→			name:    "reordered keyid",
   473→			oldKeys: VerificationKeys{DataTimestamp: time.Unix(1000, 0), Keys: []serviceaccount.PublicKey{{KeyID: "a"}, {KeyID: "b"}}},
   474→			newKeys: VerificationKeys{DataTimestamp: time.Unix(1000, 0), Keys: []serviceaccount.PublicKey{{KeyID: "b"}, {KeyID: "a"}}},
   475→			expect:  true,
   476→		},
   477→		{
   478→			name:    "changed keyid",
   479→			oldKeys: VerificationKeys{DataTimestamp: time.Unix(1000, 0), Keys: []serviceaccount.PublicKey{{KeyID: "a"}}},
   480→			newKeys: VerificationKeys{DataTimestamp: time.Unix(1000, 0), Keys: []serviceaccount.PublicKey{{KeyID: "b"}}},
   481→			expect:  true,
   482→		},
   483→		{
   484→			name:    "added key",
   485→			oldKeys: VerificationKeys{DataTimestamp: time.Unix(1000, 0), Keys: []serviceaccount.PublicKey{{KeyID: "a"}}},
   486→			newKeys: VerificationKeys{DataTimestamp: time.Unix(1000, 0), Keys: []serviceaccount.PublicKey{{KeyID: "a"}, {KeyID: "b"}}},
   487→			expect:  true,
   488→		},
   489→		{
   490→			name:    "removed key",
   491→			oldKeys: VerificationKeys{DataTimestamp: time.Unix(1000, 0), Keys: []serviceaccount.PublicKey{{KeyID: "a"}, {KeyID: "b"}}},
   492→			newKeys: VerificationKeys{DataTimestamp: time.Unix(1000, 0), Keys: []serviceaccount.PublicKey{{KeyID: "a"}}},
   493→			expect:  true,
   494→		},
   495→		{
   496→			name:    "changed oidc",
   497→			oldKeys: VerificationKeys{DataTimestamp: time.Unix(1000, 0), Keys: []serviceaccount.PublicKey{{KeyID: "a", ExcludeFromOIDCDiscovery: false}}},
   498→			newKeys: VerificationKeys{DataTimestamp: time.Unix(1000, 0), Keys: []serviceaccount.PublicKey{{KeyID: "a", ExcludeFromOIDCDiscovery: true}}},
   499→			expect:  true,
   500→		},
   501→	}
   502→	for _, tc := range testcases {
   503→		t.Run(tc.name, func(t *testing.T) {
   504→			result := keysChanged(&tc.oldKeys, &tc.newKeys)
   505→			if result != tc.expect {
   506→				t.Errorf("got %v, expected %v", result, tc.expect)
   507→			}
   508→		})
   509→	}
   510→}
